INSERT INTO `home_content` (section_key, title, subtitle, content, button_text, button_link, is_active, display_order, created_at, updated_at) VALUES
('hero', 'Dit digitale bibliotek', 'Udforsk, reservér og administrer din bogsamling', NULL, 'Udforsk kataloget', '/katalog', 1, -2, NOW(), NOW()),
('features_title', 'Hvorfor vælge Pinakes', 'En moderne, intuitiv oplevelse af biblioteksadministration, altid lige ved hånden', NULL, NULL, NULL, 1, 0, NOW(), NOW()),
('feature_1', 'Forenklet administration', 'Katalogiser dine bøger, håndter lån og afleveringer med en intuitiv og hurtig grænseflade', 'fas fa-tasks', NULL, NULL, 1, 1, NOW(), NOW()),
('feature_2', 'Komplet katalogisering', 'Importer data fra ISBN, organiser efter kategorier, generer etiketter og spor hvert fysisk eksemplar', 'fas fa-book', NULL, NULL, 1, 2, NOW(), NOW()),
('feature_3', 'Lånesystem', 'Håndter lån, forfaldsdatoer, fornyelser og automatiske e-mailnotifikationer til brugere og personale', 'fas fa-exchange-alt', NULL, NULL, 1, 3, NOW(), NOW()),
('feature_4', 'Open source og gratis', '100% gratis software uden licensomkostninger. Tilpas og bidrag til Pinakes-projektet', 'fas fa-code-branch', NULL, NULL, 1, 4, NOW(), NOW()),
('text_content', 'Πίνακες (Pinakes) – "Tavlerne"', NULL, '<p>Navnet <strong>Pinakes</strong> stammer fra det oldgræske <em>πίνακες</em> (pinakes), som betyder "tavler" eller "tabeller". Det hylder <strong>Kallimachos fra Kyrene</strong> (305-240 f.Kr.), som omkring 245 f.Kr. skabte det første systematiske bibliotekskatalog i historien for Biblioteket i Alexandria: <em>Πίνακες τῶν ἐν πάσῃ παιδείᾳ διαλαμψάντων καὶ ὧν συνέγραψαν</em> ("Tavler over dem, der har udmærket sig inden for ethvert vidensområde, og deres værker").</p><p>Dette monumentale værk, bestående af 120 ruller, organiserede systematisk over 120.000 papyrusruller i biblioteket. Selvom de originale <em>Pinakes</em> er gået tabt, har deres katalogiseringsmetode haft dybtgående indflydelse på moderne biblioteksvidenskab.</p><p>Dette projekt viderefører den årtusindgamle tradition på <strong>2.268 år</strong> ved at bringe de samme principper om organisering og tilgængelighed af viden ind i den digitale tidsalder.</p>', NULL, NULL, 1, 4, NOW(), NOW()),
('latest_books_title', 'Seneste tilføjelser', 'Opdag de seneste tilføjelser til kataloget', NULL, NULL, NULL, 1, 5, NOW(), NOW()),
('genre_carousel', 'Udforsk de vigtigste genrer', 'Udforsk vores tematiske rødder, og lad dig inspirere af de tilgængelige titler.', NULL, NULL, NULL, 1, 6, NOW(), NOW()),
('events', 'Kommende arrangementer', 'Deltag i vores næste møder', NULL, NULL, NULL, 1, 7, NOW(), NOW()),
('cta', 'Klar til at komme i gang?', 'Registrer dig nu, og begynd at udforske vores katalog', NULL, 'Registrer dig nu', '/registrer', 1, 8, NOW(), NOW());
