INSERT INTO `cms_pages` VALUES (1,'chi-siamo','da_DK','Om os','<h2>Velkommen til Pinakes</h2>\n<p>Pinakes er et moderne, intuitivt og helt gratis biblioteksadministrationssystem. Bygget til at forenkle bogkatalogisering, håndtering af lån og administration af biblioteker af enhver størrelse.</p>\n\n<h3>🎯 Vores mission</h3>\n<p>At gøre biblioteksadministration tilgængelig for alle, uden licensomkostninger eller begrænsninger. Pinakes er 100% open source, frit og gratis for alle.</p>\n\n<h3>✨ Vigtigste funktioner</h3>\n<ul>\n    <li><strong>Smart katalogisering:</strong> Importer automatisk data fra ISBN, organiser efter kategorier, forfattere og brugerdefinerede klassifikationer</li>\n    <li><strong>Lånehåndtering:</strong> Komplet system til håndtering af lån, forfaldsdatoer, fornyelser og afleveringer</li>\n    <li><strong>Automatiske notifikationer:</strong> Påmindelser via e-mail om lånefrister og kommunikation med brugerne</li>\n    <li><strong>Moderne grænseflade:</strong> Responsivt design optimeret til computer, tablet og smartphone</li>\n    <li><strong>100% open source:</strong> Fri kode, tilpasningsbar og uden skjulte omkostninger</li>\n</ul>\n\n<h3>🚀 Hvorfor vælge Pinakes?</h3>\n<p>Pinakes opstod ud fra behovet for at tilbyde et professionelt, pålideligt og gratis værktøj til administration af skolebiblioteker, foreninger og private samlinger. Du behøver ikke være it-ekspert: den intuitive grænseflade gør det muligt for alle at komme i gang med det samme.</p>\n\n<h3>📖 Kom i gang i dag</h3>\n<p>Tilpas denne side med oplysninger om dit bibliotek, dit team og dine services. Gå til admin-panelet (CMS &gt; Sider) for at redigere dette indhold og gøre det unikt.</p>\n\n<p><em>Dette er eksempelindhold. Tilpas det for at fortælle historien om dit bibliotek!</em></p>',NULL,NULL,1,'2025-10-01 10:35:27','2025-10-01 10:35:27');
INSERT INTO `cms_pages` VALUES (2,'privacy-policy','da_DK','Privatlivspolitik','<h2>Privatlivspolitik</h2>\n<p>Dette er en pladsholderside for privatlivspolitikken. Tilpas dette indhold i henhold til gældende lovgivning (GDPR) og de specifikke behov i dit bibliotek.</p>\n\n<h3>1. Dataansvarlig</h3>\n<p>[Indsæt oplysninger om den dataansvarlige her: navn, adresse, e-mail, telefon]</p>\n\n<h3>2. Indsamlede data</h3>\n<p>Personoplysninger indsamlet gennem dette system omfatter:</p>\n<ul>\n    <li>Personoplysninger (navn, efternavn, fødselsdato)</li>\n    <li>Kontaktoplysninger (e-mail, telefon, adresse)</li>\n    <li>Data vedrørende foretagne lån</li>\n</ul>\n\n<h3>3. Formål med behandlingen</h3>\n<p>Data behandles udelukkende til:</p>\n<ul>\n    <li>Administration af brugerregister</li>\n    <li>Administration af biblioteksudlån</li>\n    <li>Afsendelse af lånerelateret kommunikation (forfaldsdatoer, fornyelser)</li>\n</ul>\n\n<h3>4. Den registreredes rettigheder</h3>\n<p>Brugere har ret til at få adgang til deres data samt anmode om berigtigelse, sletning eller begrænsning af behandlingen, som fastsat i Forordning (EU) 2016/679 (GDPR).</p>\n\n<p><strong>VIGTIGT:</strong> Dette er en eksempelskabelon. Kontakt en juridisk rådgiver for at udarbejde en privatlivspolitik, der overholder gældende lovgivning.</p>\n\n<p><em>Gå til admin-panelet (CMS &gt; Sider) for at tilpasse denne side.</em></p>',NULL,NULL,1,'2025-10-01 10:35:27','2025-10-01 10:35:27');
INSERT INTO `email_templates` VALUES (1,'admin_new_registration','da_DK','👤 Ny registreringsanmodning','\n            <h2>Ny registreringsanmodning</h2>\n            <p>En ny bruger har anmodet om adgang til Pinakes:</p>\n            <p><strong>Brugeroplysninger:</strong></p>\n            <ul>\n                <li>Navn: {{nome}} {{cognome}}</li>\n                <li>Email: {{email}}</li>\n                <li>Medlemskort: {{codice_tessera}}</li>\n                <li>Anmodningsdato: {{data_registrazione}}</li>\n            </ul>\n            <p><a href="{{admin_users_url}}" style="background-color: #3b82f6; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;">Administrer Brugere</a></p>\n        ','Email inviata agli admin quando un nuovo utente si registra.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (2,'admin_new_review','da_DK','⭐ Ny anmeldelse afventer godkendelse','<h2>Ny anmeldelse afventer godkendelse</h2>\n<p>Der er modtaget en ny anmeldelse af bogen:</p>\n<p><strong>Bog:</strong> {{libro_titolo}}</p>\n<div style="background-color: #fff7ed; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #f59e0b;">\n    <p><strong>Bedømmelse:</strong> {{stelle}} stjerner ⭐</p>\n    <p><strong>Bruger:</strong> {{utente_nome}} ({{utente_email}})</p>\n    <p><strong>Anmeldelsesdato:</strong> {{data_recensione}}</p>\n    <p><strong>Titel:</strong> {{titolo_recensione}}</p>\n    <p><strong>Beskrivelse:</strong></p>\n    <p style="white-space: pre-line;">{{descrizione_recensione}}</p>\n</div>\n<p style="text-align: center;">\n    <a href="{{link_approvazione}}" style="background-color: #10b981; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;">Administrer Anmeldelse</a>\n</p>\n<p><em>For at godkende eller afvise denne anmeldelse skal du logge ind i administrationspanelet.</em></p>','Inviata agli amministratori quando viene ricevuta una nuova recensione da approvare.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (3,'loan_approved','da_DK','✅ Din udlånsanmodning er blevet godkendt!','<h2>Din udlånsanmodning er blevet godkendt!</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi er glade for at kunne fortælle dig, at din udlånsanmodning er blevet <strong>godkendt</strong>!</p>\n<p><strong>Lånedetaljer:</strong></p>\n<ul>\n    <li>Bog: {{libro_titolo}}</li>\n    <li>Startdato for lån: {{data_inizio}}</li>\n    <li>Udløbsdato: {{data_fine}}</li>\n    <li>Varighed: {{giorni_prestito}} dage</li>\n</ul>\n<div style="background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;">\n    <p><strong>📦 Afhentning af bogen</strong></p>\n    <p>{{pickup_instructions}}</p>\n</div>\n<p><strong>Vigtigt:</strong> Husk at aflevere bogen inden udløbsdatoen. Du vil modtage en påmindelse et par dage før udløbet.</p>\n<p>God fornøjelse med læsningen!</p>','Inviata all\'utente quando un amministratore approva una richiesta di prestito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (4,'loan_rejected','da_DK','❌ Din udlånsanmodning er ikke blevet godkendt','<h2>Din udlånsanmodning er ikke blevet godkendt</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi må desværre meddele dig, at din udlånsanmodning for bogen <strong>"{{libro_titolo}}"</strong> ikke er blevet godkendt.</p>\n<div style="background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;">\n    <p><strong>Årsag:</strong></p>\n    <p>{{motivo_rifiuto}}</p>\n</div>\n<p>Hvis du har spørgsmål eller ønsker yderligere oplysninger, er du velkommen til at kontakte os.</p>\n<p>Med venlig hilsen,<br>Biblioteksteamet</p>','Inviata all\'utente quando un amministratore rifiuta una richiesta di prestito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (5,'loan_expiring_warning','da_DK','⚠️ Dit lån udløber snart','\n            <h2>Påmindelse om udløb af lån</h2>\n            <p>Hej {{utente_nome}},</p>\n            <p>Vi minder dig om, at dit lån snart udløber:</p>\n            <p><strong>Lånedetaljer:</strong></p>\n            <ul>\n                <li>Bog: {{libro_titolo}}</li>\n                <li>Udløbsdato: {{data_scadenza}}</li>\n                <li>Dage tilbage: {{giorni_rimasti}}</li>\n            </ul>\n            <div style="background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;">\n                <p><strong>⏰ Handling påkrævet</strong></p>\n                <p>For at undgå gebyrer skal du aflevere bogen inden udløbsdatoen eller kontakte biblioteket for en eventuel fornyelse.</p>\n            </div>\n            <p>Tak for samarbejdet!</p>\n        ','Email inviata all\'utente 3 giorni prima della scadenza del prestito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (6,'loan_overdue_admin','da_DK','Lån #{{prestito_id}} er forsinket','<h2>Forsinket lån</h2>\n<p>Lånet <strong>#{{prestito_id}}</strong> er nu i status <strong>forsinket</strong>.</p>\n<ul>\n  <li><strong>Bog:</strong> {{libro_titolo}}</li>\n  <li><strong>Bruger:</strong> {{utente_nome}} ({{utente_email}})</li>\n  <li><strong>Lånedato:</strong> {{data_prestito}}</li>\n  <li><strong>Udløbsdato:</strong> {{data_scadenza}}</li>\n</ul>\n<p>Grib ind for at kontakte brugeren og rykke for aflevering.</p>','Avvisa gli amministratori quando un prestito entra in ritardo.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (7,'loan_overdue_notification','da_DK','🚨 Lån udløbet - Handling påkrævet','\n            <h2>Lån udløbet</h2>\n            <p>Hej {{utente_nome}},</p>\n            <p>Dit lån er udløbet og skal afleveres omgående:</p>\n            <p><strong>Lånedetaljer:</strong></p>\n            <ul>\n                <li>Bog: {{libro_titolo}}</li>\n                <li>Udløbsdato: {{data_scadenza}}</li>\n                <li>Dage forsinket: {{giorni_ritardo}}</li>\n            </ul>\n            <div style="background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;">\n                <p><strong>🚨 Akut handling påkrævet</strong></p>\n                <p>Bogen skal afleveres omgående. Forsinket aflevering kan medføre sanktioner og suspendering af tjenesten.</p>\n            </div>\n            <p>Kontakt biblioteket omgående for at løse situationen.</p>\n        ','Email inviata all\'utente quando il prestito è scaduto.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (8,'loan_request_notification','da_DK','📚 Ny udlånsanmodning','\n            <h2>Ny udlånsanmodning</h2>\n            <p>Der er modtaget en ny udlånsanmodning:</p>\n            <p><strong>Detaljer:</strong></p>\n            <ul>\n                <li>Bog: {{libro_titolo}}</li>\n                <li>Bruger: {{utente_nome}} ({{utente_email}})</li>\n                <li>Ønsket startdato: {{data_inizio}}</li>\n                <li>Ønsket slutdato: {{data_fine}}</li>\n                <li>Anmodningsdato: {{data_richiesta}}</li>\n            </ul>\n            <p><a href="{{approve_url}}" style="background-color: #10b981; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;">Administrer Anmodning</a></p>\n        ','Email inviata agli admin quando un utente richiede un prestito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (9,'user_account_approved','da_DK','Konto godkendt - Velkommen til biblioteket!','\n            <h2>Din konto er blevet godkendt!</h2>\n            <p>Hej {{nome}} {{cognome}},</p>\n            <p>Vi er glade for at kunne fortælle dig, at din konto er blevet godkendt af en administrator.</p>\n            <p>Du kan nu logge ind på systemet og begynde at booke bøger!</p>\n            <p><strong>Detaljer om din konto:</strong></p>\n            <ul>\n                <li>Email: {{email}}</li>\n                <li>Medlemskort: {{codice_tessera}}</li>\n            </ul>\n            <p><a href="{{login_url}}" style="background-color: #3b82f6; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;">Log ind nu</a></p>\n            <p>Velkommen til vores digitale bibliotek!</p>\n        ','Email inviata quando un admin approva direttamente l\'account senza richiedere verifica email.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (10,'user_activation_with_verification','da_DK','Aktivér din konto - Bekræft email','\n            <h2>Din konto er blevet godkendt!</h2>\n            <p>Hej {{nome}} {{cognome}},</p>\n            <p>Vi er glade for at kunne fortælle dig, at din konto er blevet godkendt af en administrator.</p>\n            <p>📧 <strong>Bekræft din email</strong></p>\n            <p>For at fuldføre aktiveringen skal du klikke på knappen nedenfor for at bekræfte din emailadresse:</p>\n            <p style="text-align: center; margin: 30px 0;">\n                <a href="{{verification_url}}" style="background-color: #10b981; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block;">✅ Bekræft Email</a>\n            </p>\n            <p><strong>Detaljer om din konto:</strong></p>\n            <ul>\n                <li>Email: {{email}}</li>\n                <li>Medlemskort: {{codice_tessera}}</li>\n            </ul>\n            <div style="background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;">\n                <p><strong>⏰ Vigtigt</strong></p>\n                <p>Bekræftelseslinket er gyldigt i 7 dage. Efter bekræftelsen kan du logge ind på systemet og booke bøger.</p>\n            </div>\n            <p>Hvis du ikke har anmodet om denne registrering, kan du se bort fra denne email.</p>\n        ','Email inviata quando un admin approva l\'account richiedendo la verifica email.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (11,'user_registration_pending','da_DK','Registrering modtaget - Afventer godkendelse','\n            <h2>Velkommen {{nome}} {{cognome}}!</h2>\n            <p>Din registreringsanmodning er blevet modtaget.</p>\n            <p><strong>Kontodetaljer:</strong></p>\n            <ul>\n                <li>Email: {{email}}</li>\n                <li>Medlemskort: {{codice_tessera}}</li>\n                <li>Registreringsdato: {{data_registrazione}}</li>\n            </ul>\n            {{sezione_verifica}}\n            <div style="background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;">\n                <p><strong>⏳ Konto afventer godkendelse</strong></p>\n                <p>Din konto afventer godkendelse af en administrator.\n                Du vil modtage en bekræftelsesmail, når kontoen er blevet aktiveret.</p>\n            </div>\n            <p>Tak, fordi du valgte Pinakes!</p>\n        ','Email inviata all\'utente dopo la registrazione, quando l\'account è in attesa di approvazione.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (12,'wishlist_book_available','da_DK','📖 Bog fra din ønskeliste er nu tilgængelig!','\n            <h2>Gode nyheder!</h2>\n            <p>Hej {{utente_nome}},</p>\n            <p>Bogen, du tilføjede til din ønskeliste, er nu tilgængelig til udlån:</p>\n            <div style="background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;">\n                <h3 style="color: #1e40af; margin: 0 0 10px 0;">{{libro_titolo}}</h3>\n                <p style="margin: 5px 0;"><strong>Forfatter:</strong> {{libro_autore}}</p>\n                <p style="margin: 5px 0;"><strong>ISBN:</strong> {{libro_isbn}}</p>\n                <p style="margin: 5px 0;"><strong>Tilgængelig fra:</strong> {{data_disponibilita}}</p>\n            </div>\n            <div style="background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0;">\n                <p><strong>✨ Reservér med det samme!</strong></p>\n                <p>Bogen er nu tilgængelig til reservation. Skynd dig, før en anden reserverer den!</p>\n            </div>\n            <p style="text-align: center;">\n                <a href="{{book_url}}" style="background-color: #10b981; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;">📚 Reservér Nu</a>\n                <a href="{{wishlist_url}}" style="background-color: #6b7280; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;">❤️ Administrér Ønskeliste</a>\n            </p>\n            <p><em>Bogen bliver på din ønskeliste; du vil ikke modtage flere notifikationer om denne titel.</em></p>\n        ','Email inviata quando un libro della wishlist diventa disponibile.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (13,'reservation_book_available','da_DK','📚 Reserveret bog klar til afhentning!','<h2>Din bog er klar til afhentning!</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi er glade for at kunne informere dig om, at bogen, du havde reserveret, nu er tilgængelig og klar til afhentning:</p>\n<div style="background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;">\n    <h3 style="color: #1e40af; margin: 0 0 10px 0;">{{libro_titolo}}</h3>\n    <p style="margin: 5px 0;"><strong>Forfatter:</strong> {{libro_autore}}</p>\n    <p style="margin: 5px 0;"><strong>ISBN:</strong> {{libro_isbn}}</p>\n    <p style="margin: 5px 0;"><strong>Lånperiode:</strong> {{data_inizio}} - {{data_fine}}</p>\n</div>\n<div style="background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;">\n    <p><strong>📦 Næste skridt</strong></p>\n    <p>Kom forbi biblioteket for at hente bogen. Husk at medbringe et gyldigt legitimationsdokument.</p>\n</div>\n<p style="text-align: center;">\n    <a href="{{book_url}}" style="background-color: #3b82f6; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;">📖 Se Bog</a>\n    <a href="{{profile_url}}" style="background-color: #6b7280; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;">👤 Mine Lån</a>\n</p>\n<p><em>Reservationen er blevet konverteret til et lån, der afventer bekræftelse af afhentning.</em></p>','Email inviata quando un libro prenotato diventa disponibile e viene convertito in prestito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (14,'user_password_setup','da_DK','🔐 Opret din adgangskode','<h2>Opret din adgangskode</h2>\n<p>Hej {{nome}} {{cognome}},</p>\n<p>Din konto på <strong>{{app_name}}</strong> er blevet oprettet. For at begynde at bruge systemet skal du oprette din adgangskode.</p>\n<div style="background-color: #f0f9ff; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #3b82f6;">\n    <p><strong>🔑 Konfigurér din konto</strong></p>\n    <p>Klik på knappen nedenfor for at oprette din adgangskode:</p>\n</div>\n<p style="text-align: center; margin: 30px 0;">\n    <a href="{{reset_url}}" style="background-color: #10b981; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block;">🔐 Opret Adgangskode</a>\n</p>\n<div style="background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;">\n    <p><strong>⏰ Vigtigt</strong></p>\n    <p>Linket er gyldigt i 24 timer. Hvis det udløber, bedes du kontakte en administrator for at få et nyt.</p>\n</div>\n<p>Hvis du ikke har anmodet om denne e-mail, kan du se bort fra den.</p>','Email inviata ai nuovi utenti per impostare la password del loro account.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (15,'admin_invitation','da_DK','🎉 Invitation som Administrator','<h2>Velkommen til teamet!</h2>\n<p>Hej {{nome}} {{cognome}},</p>\n<p>Du er blevet inviteret som administrator på <strong>{{app_name}}</strong>.</p>\n<div style="background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;">\n    <h3 style="color: #1e40af; margin: 0 0 10px 0;">Dine adgangsrettigheder</h3>\n    <p>Som administrator vil du have adgang til:</p>\n    <ul>\n        <li>Administration af bogkatalog</li>\n        <li>Administration af brugere og lån</li>\n        <li>Systemindstillinger</li>\n        <li>Rapporter og statistik</li>\n    </ul>\n</div>\n<p><strong>Sådan kommer du i gang:</strong></p>\n<ol>\n    <li>Opret din adgangskode ved at klikke på knappen nedenfor</li>\n    <li>Log ind på administrationspanelet</li>\n</ol>\n<p style="text-align: center; margin: 30px 0;">\n    <a href="{{reset_url}}" style="background-color: #10b981; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block; margin: 10px;">🔐 Opret Adgangskode</a>\n    <a href="{{dashboard_url}}" style="background-color: #3b82f6; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block; margin: 10px;">📊 Admin Dashboard</a>\n</p>\n<div style="background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;">\n    <p><strong>⏰ Vigtigt</strong></p>\n    <p>Linket til oprettelse af adgangskode er gyldigt i 24 timer.</p>\n</div>\n<p>Velkommen til teamet!</p>','Email inviata quando un utente viene invitato come amministratore.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (16,'loan_pickup_ready','da_DK','📦 Bog klar til afhentning!','<h2>Bog klar til afhentning!</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi er glade for at kunne informere dig om, at din bog er klar til afhentning!</p>\n<div style="background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;">\n    <h3 style="color: #1e40af; margin: 0 0 10px 0;">{{libro_titolo}}</h3>\n    <p style="margin: 5px 0;"><strong>Lånperiode:</strong> {{data_inizio}} - {{data_fine}}</p>\n    <p style="margin: 5px 0;"><strong>Varighed:</strong> {{giorni_prestito}} dage</p>\n</div>\n<div style="background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #f59e0b;">\n    <p><strong>⏰ Afhentningsfrist: {{scadenza_ritiro}}</strong></p>\n    <p>Afhent bogen inden denne dato, ellers annulleres lånet automatisk.</p>\n</div>\n<div style="background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;">\n    <p><strong>📦 Sådan afhenter du</strong></p>\n    <p>{{pickup_instructions}}</p>\n</div>\n<p>God fornøjelse med læsningen!</p>','Inviata quando un prestito è stato approvato e il libro è pronto per il ritiro.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (17,'loan_pickup_expired','da_DK','⏰ Afhentningsfristen er udløbet','<h2>Afhentningsfristen er udløbet</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Desværre har du ikke afhentet bogen inden for den fastsatte frist.</p>\n<div style="background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;">\n    <p><strong>Bog:</strong> {{libro_titolo}}</p>\n    <p><strong>Afhentningsfrist:</strong> {{scadenza_ritiro}}</p>\n</div>\n<p>Lånet er automatisk blevet annulleret, og bogen er blevet gjort tilgængelig for andre brugere.</p>\n<p>Hvis du stadig ønsker denne bog, opfordrer vi dig til at indsende en ny låneanmodning.</p>\n<p>Med venlig hilsen,<br>Bibliotekets team</p>','Inviata quando il tempo per ritirare un libro è scaduto e il prestito è stato annullato.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (18,'loan_pickup_cancelled','da_DK','❌ Afhentning annulleret','<h2>Afhentning annulleret</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi informerer dig om, at afhentningen af følgende bog er blevet annulleret:</p>\n<div style="background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;">\n    <p><strong>Bog:</strong> {{libro_titolo}}</p>\n    <p><strong>Årsag:</strong> {{motivo}}</p>\n</div>\n<p>Bogen er blevet gjort tilgængelig for andre brugere. Hvis du stadig ønsker denne bog, opfordrer vi dig til at indsende en ny låneanmodning.</p>\n<p>Med venlig hilsen,<br>Bibliotekets team</p>','Inviata quando un ritiro viene annullato dall''amministratore.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (19,'loan_returned','da_DK','✅ Aflevering bekræftet','<h2>Aflevering bekræftet</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi bekræfter afleveringen af følgende bog. Tak!</p>\n<div style="background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;">\n    <p><strong>Bog:</strong> {{libro_titolo}}</p>\n    <p><strong>Afleveringsdato:</strong> {{data_restituzione}}</p>\n</div>\n<p>Vi håber, du nød læsningen. Vi ses snart på biblioteket!</p>\n<p>Med venlig hilsen,<br>Bibliotekets team</p>','Inviata all\'utente quando un prestito viene registrato come restituito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (20,'reservation_expired','da_DK','⌛ Reservationen er udløbet','<h2>Reservationen er udløbet</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Din reservation af følgende bog er udløbet og er blevet lukket automatisk:</p>\n<div style="background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;">\n    <p><strong>Bog:</strong> {{libro_titolo}}</p>\n    <p><strong>Udløbet den:</strong> {{data_scadenza}}</p>\n</div>\n<p>Hvis du stadig er interesseret, kan du foretage en ny reservation når som helst.</p>\n<p>Med venlig hilsen,<br>Bibliotekets team</p>','Inviata all\'utente quando una prenotazione scade automaticamente senza essere stata convertita in prestito.',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (21,'copy_unavailable_user','da_DK','ℹ️ Opdatering om din reservation','<h2>Opdatering om din reservation</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi informerer dig om, at det eksemplar, der var reserveret til din reservation af følgende bog, ikke længere er tilgængeligt:</p>\n<div style="background-color: #fffbeb; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #f59e0b;">\n    <p><strong>Bog:</strong> {{libro_titolo}}</p>\n    <p><strong>Årsag:</strong> {{motivo}}</p>\n</div>\n<p>Vi forsøger at tildele dig et andet eksemplar hurtigst muligt. Hvis der ikke bliver flere eksemplarer tilgængelige, forbliver din reservation i køen, og vi giver dig besked, så snart bogen igen er tilgængelig.</p>\n<p>Vi beklager ulejligheden.</p>\n<p>Med venlig hilsen,<br>Bibliotekets team</p>','Inviata all\'utente quando la copia riservata per la sua prenotazione diventa indisponibile (persa o danneggiata).',1,NULL,NULL);
INSERT INTO `email_templates` VALUES (22,'reservation_cancelled','da_DK','❌ Reservation annulleret','<h2>Reservation annulleret</h2>\n<p>Hej {{utente_nome}},</p>\n<p>Vi informerer dig om, at din reservation af følgende bog er blevet annulleret:</p>\n<div style="background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;">\n    <p><strong>Bog:</strong> {{libro_titolo}}</p>\n    <p><strong>Årsag:</strong> {{motivo}}</p>\n</div>\n<p>Hvis du stadig ønsker denne bog, kan du foretage en ny reservation når som helst.</p>\n<p>Med venlig hilsen,<br>Bibliotekets team</p>','Inviata all\'utente quando una prenotazione viene annullata dall\'amministrazione.',1,NULL,NULL);
